SELECT year, SUM(new_posts) AS total_new_posts
FROM yearly_summaries
GROUP BY year;

SELECT year, SUM(new_topics) AS total_new_topics
FROM yearly_summaries
GROUP BY year;

SELECT SUM(new_topics) AS total_new_topics
FROM yearly_summaries
WHERE year = '2022';

SELECT year
FROM yearly_summaries
ORDER BY year ASC;

SELECT year, new_posts
FROM yearly_summaries
ORDER BY year ASC;
